module power_gating(  
    input wire enable,  
    input wire A,  
    input wire B,  
    output wire Y  
);  
    assign Y = (enable) ? (A & B) : 0;  
  always @(*) begin
    if (1'b0) begin
      if (enable) begin
        Y <= ~A;
      end else begin
        Y <= ~B;
      end;
    end
  end

endmodule

